std::string run_test(const std::string& input_title, const std::string& input_author, double initial_price, double test_price) {
    std::string title = input_title;
    std::string author = input_author;
    Book book(title, author, initial_price);
    book.setPrice(test_price);

    std::ostringstream oss;
    oss.precision(10);
    oss << book.getPrice();
    return oss.str();
}

int main() {
    std::string line;
    while (std::getline(std::cin, line)) {
        std::stringstream ss(line);
        std::string title, author, initial_price_str, test_price_str;
        std::getline(ss, title, ',');
        std::getline(ss, author, ',');
        std::getline(ss, initial_price_str, ',');
        std::getline(ss, test_price_str, ',');
        double initial_price = std::stod(initial_price_str);
        double test_price = std::stod(test_price_str);
        std::cout << run_test(title, author, initial_price, test_price) << std::endl;
    }
    return 0;
}
